Architecture Diagram
flowchart LR
  classDef data fill:#1d2736,stroke:#5a6f8c,color:#e8edf5;
  classDef core fill:#243247,stroke:#8ebfd2,color:#eef4ff;
  classDef state fill:#2d2a3f,stroke:#9f90d8,color:#f1ecff;
  classDef output fill:#2b3a33,stroke:#9bc7ae,color:#ebf8f0;

  subgraph IN[INPUTS]
    A[LearnUS files]
    B[Research papers]
    C[Notes and manuals]
    D[Drafts and outputs]
  end

  IN --&gt; GCLI[Gemini CLI plus gws\nclassify, rename, route, update context]
  GCLI --&gt; GD[Google Drive\nshared memory layer]

  GD --&gt; KT[Knowledge tools\nNotebookLM, Perplexity, Zotero manual]
  GD --&gt; ET[Execution tools\nClaude, ChatGPT/Codex, Claude Code]
  GD --&gt; GH[GitHub\ncode state]

  KT --&gt; OUT2[Research and analysis]
  ET --&gt; OUT1[Design and implementation]

  class A,B,C,D data;
  class GCLI,GD core;
  class GH state;
  class KT,ET,OUT1,OUT2 output;
